// ── Helpers ────────────────────────────────────────────────────────────────

function fmtEUR(n: number): string {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency', currency: 'EUR',
    minimumFractionDigits: 2, maximumFractionDigits: 2,
  }).format(n);
}

function fmtCrypto(n: number): string {
  return new Intl.NumberFormat('fr-FR', {
    minimumFractionDigits: 2, maximumFractionDigits: 8,
  }).format(n);
}

function parseDDMMYYYY(str: string): Date | null {
  const parts = str.trim().split('/');
  if (parts.length !== 3) return null;
  const d = parseInt(parts[0], 10), m = parseInt(parts[1], 10), y = parseInt(parts[2], 10);
  if (isNaN(d) || isNaN(m) || isNaN(y)) return null;
  const date = new Date(y, m - 1, d);
  return isNaN(date.getTime()) ? null : date;
}

function periodLabel(purchases: number, freq: string): string {
  if (freq === 'once') return 'en one-shot';
  if (freq === 'daily') return `en ${purchases} jour${purchases > 1 ? 's' : ''}`;
  if (freq === 'weekly') return `en ${purchases} semaine${purchases > 1 ? 's' : ''}`;
  return `en ${purchases} mois`;
}

function formatDateInput(value: string): string {
  const digits = value.replace(/\D/g, '').slice(0, 8);
  if (digits.length <= 2) return digits;
  if (digits.length <= 4) return `${digits.slice(0, 2)}/${digits.slice(2)}`;
  return `${digits.slice(0, 2)}/${digits.slice(2, 4)}/${digits.slice(4)}`;
}

function ChartTooltip({ active, payload, label }: any) {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ fontFamily: 'Lexend, sans-serif' }} className="bg-[#0d1629] border border-white/10 rounded-xl px-4 py-3 shadow-xl">
      <p className="text-white/50 text-xs mb-2">{label}</p>
      {(payload as any[]).map((entry: any) => (
        <p key={entry.dataKey} className="text-xs mb-0.5" style={{ color: entry.color }}>
          {entry.name}&nbsp;: {fmtEUR(entry.value)}
        </p>
      ))}
    </div>
  );
}

// ── Info Bubble ────────────────────────────────────────────────────────────

function InfoBubble({ text }: { text: string }) {
  return (
    <span className="relative group/info inline-flex items-center">
      <span className="w-4 h-4 rounded-full border border-[#1098F7] text-[#1098F7] text-[9px] flex items-center justify-center cursor-help select-none font-normal leading-none">i</span>
      <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-56 bg-[#0d1629] border border-white/10 text-white text-xs rounded-xl px-3 py-2 shadow-xl pointer-events-none opacity-0 group-hover/info:opacity-100 transition-opacity duration-200 z-50 text-left leading-relaxed whitespace-normal">
        {text}
      </span>
    </span>
  );
}

